import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Teacher {
  id: string;
  name: string;
  title: string;
  maxSlots: number;
}

export interface Registration {
  id: string;
  studentName: string;
  studentId: string;
  teacherId: string;
  timestamp: number;
}

export interface TeacherStatus extends Teacher {
  currentRegistrations: number;
}

import { Teacher } from './types';

export const TEACHERS: Teacher[] = [
  { id: '1', name: 'TS. TRẦN KIỀU MỸ AN', title: 'Tiến sĩ', maxSlots: 2 },
  { id: '2', name: 'PGS.TS PHẠM VŨ PHI HỔ', title: 'Phó Giáo sư, Tiến sĩ', maxSlots: 2 },
  { id: '3', name: 'TS. NGUYỄN XUÂN HỒNG', title: 'Tiến sĩ', maxSlots: 2 },
  { id: '4', name: 'TS. TRƯƠNG TRẦN MINH NHẬT', title: 'Tiến sĩ', maxSlots: 2 },
  { id: '5', name: 'TS. PHAN THỊ TUYẾT NGA', title: 'Tiến sĩ', maxSlots: 2 },
  { id: '6', name: 'TS. NGUYỄN TRƯỜNG SA', title: 'Tiến sĩ', maxSlots: 2 },
  { id: '7', name: 'PGS.TS NGUYỄN THANH TÙNG', title: 'Phó Giáo sư, Tiến sĩ', maxSlots: 2 },
];

export const MAX_SLOTS_PER_TEACHER = 2;
export const LOCAL_STORAGE_KEY = 'teacher_registrations_v1';

import React, { useState, useEffect, useCallback } from 'react';
import { TEACHERS, LOCAL_STORAGE_KEY } from './constants';
import { Registration, TeacherStatus } from './types';
import RegistrationForm from './components/RegistrationForm';
import TeacherGrid from './components/TeacherGrid';
import RegistrationList from './components/RegistrationList';

const App: React.FC = () => {
  const [registrations, setRegistrations] = useState<Registration[]>([]);
  const [activeTab, setActiveTab] = useState<'register' | 'list'>('register');
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  // Initialize data from local storage
  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        setRegistrations(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse registrations", e);
      }
    }
  }, []);

  // Save to local storage whenever registrations change
  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(registrations));
  }, [registrations]);

  const handleRegister = useCallback((studentName: string, studentId: string, teacherId: string) => {
    // Validation
    const teacherRegs = registrations.filter(r => r.teacherId === teacherId);
    if (teacherRegs.length >= 2) {
      setNotification({ type: 'error', message: 'Giáo viên này đã nhận đủ số lượng sinh viên.' });
      return;
    }

    const alreadyRegistered = registrations.find(r => r.studentId === studentId);
    if (alreadyRegistered) {
      setNotification({ type: 'error', message: 'Mã số sinh viên này đã đăng ký rồi.' });
      return;
    }

    const newRegistration: Registration = {
      id: Math.random().toString(36).substr(2, 9),
      studentName,
      studentId,
      teacherId,
      timestamp: Date.now(),
    };

    setRegistrations(prev => [...prev, newRegistration]);
    setNotification({ type: 'success', message: 'Đăng ký giáo viên hướng dẫn thành công!' });
    setTimeout(() => setActiveTab('list'), 1500);
  }, [registrations]);

  const handleDelete = useCallback((regId: string) => {
    if (window.confirm("Bạn có chắc chắn muốn hủy đăng ký này?")) {
      setRegistrations(prev => prev.filter(r => r.id !== regId));
      setNotification({ type: 'success', message: 'Đã hủy đăng ký thành công.' });
    }
  }, []);

  const getTeacherStatus = (): TeacherStatus[] => {
    return TEACHERS.map(t => ({
      ...t,
      currentRegistrations: registrations.filter(r => r.teacherId === t.id).length
    }));
  };

  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-indigo-700 text-white shadow-lg">
        <div className="max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row md:items-center md:justify-between">
            <div>
              <h1 className="text-3xl font-extrabold tracking-tight">Hệ Thống Đăng Ký</h1>
              <p className="mt-1 text-indigo-100 font-medium">Lựa chọn Giáo viên hướng dẫn cho Đồ án/Khóa luận</p>
            </div>
            <div className="mt-4 md:mt-0 flex space-x-2">
              <button 
                onClick={() => setActiveTab('register')}
                className={`px-4 py-2 rounded-md font-medium transition-colors ${activeTab === 'register' ? 'bg-white text-indigo-700' : 'bg-indigo-600 hover:bg-indigo-500'}`}
              >
                <i className="fas fa-edit mr-2"></i>Đăng ký
              </button>
              <button 
                onClick={() => setActiveTab('list')}
                className={`px-4 py-2 rounded-md font-medium transition-colors ${activeTab === 'list' ? 'bg-white text-indigo-700' : 'bg-indigo-600 hover:bg-indigo-500'}`}
              >
                <i className="fas fa-list-ul mr-2"></i>Danh sách
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow container mx-auto px-4 py-8">
        {/* Notification Toast */}
        {notification && (
          <div className={`fixed top-4 right-4 z-50 p-4 rounded-lg shadow-xl flex items-center space-x-3 animate-bounce ${notification.type === 'success' ? 'bg-green-100 text-green-800 border-l-4 border-green-500' : 'bg-red-100 text-red-800 border-l-4 border-red-500'}`}>
            <i className={`fas ${notification.type === 'success' ? 'fa-check-circle' : 'fa-exclamation-circle'}`}></i>
            <span className="font-medium">{notification.message}</span>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Status Sidebar */}
          <div className="lg:col-span-1 space-y-6">
             <div className="bg-white rounded-xl shadow-md p-6 border border-slate-200">
               <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center">
                 <i className="fas fa-users-viewfinder text-indigo-600 mr-2"></i>
                 Trạng thái các slot
               </h2>
               <div className="space-y-4">
                 {getTeacherStatus().map(t => (
                   <div key={t.id} className="space-y-1">
                     <div className="flex justify-between text-sm">
                       <span className="font-semibold text-slate-700 truncate mr-2" title={t.name}>{t.name}</span>
                       <span className={`font-medium ${t.currentRegistrations >= t.maxSlots ? 'text-red-500' : 'text-green-600'}`}>
                         {t.currentRegistrations}/{t.maxSlots}
                       </span>
                     </div>
                     <div className="w-full bg-slate-100 rounded-full h-2">
                       <div 
                        className={`h-2 rounded-full transition-all duration-500 ${t.currentRegistrations >= t.maxSlots ? 'bg-red-500' : 'bg-indigo-500'}`} 
                        style={{ width: `${(t.currentRegistrations / t.maxSlots) * 100}%` }}
                       ></div>
                     </div>
                   </div>
                 ))}
               </div>
             </div>

             <div className="bg-indigo-50 rounded-xl p-6 border border-indigo-100">
               <h3 className="font-bold text-indigo-900 mb-2">Quy định đăng ký:</h3>
               <ul className="text-sm text-indigo-800 space-y-2 list-disc list-inside">
                 <li>Mỗi giảng viên chỉ nhận tối đa 02 sinh viên.</li>
                 <li>Sinh viên chỉ được đăng ký 01 giảng viên duy nhất.</li>
                 <li>Cần nhập chính xác Mã số sinh viên (MSSV).</li>
                 <li>Trong trường hợp hết chỗ, vui lòng liên hệ văn phòng khoa.</li>
               </ul>
             </div>
          </div>

          {/* Tab Content */}
          <div className="lg:col-span-2">
            {activeTab === 'register' ? (
              <div className="bg-white rounded-xl shadow-md p-8 border border-slate-200">
                <h2 className="text-2xl font-bold text-slate-800 mb-6">Thông tin đăng ký mới</h2>
                <RegistrationForm teachers={getTeacherStatus()} onSubmit={handleRegister} />
              </div>
            ) : (
              <div className="bg-white rounded-xl shadow-md border border-slate-200 overflow-hidden">
                <div className="p-6 border-b border-slate-200 flex justify-between items-center">
                  <h2 className="text-2xl font-bold text-slate-800">Danh sách đăng ký</h2>
                  <span className="bg-indigo-100 text-indigo-800 py-1 px-3 rounded-full text-sm font-bold">
                    Tổng: {registrations.length}
                  </span>
                </div>
                <RegistrationList 
                  registrations={registrations} 
                  teachers={TEACHERS} 
                  onDelete={handleDelete}
                />
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-slate-800 text-slate-400 py-8 mt-12">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-sm">© 2024 Khoa Công nghệ Thông tin - Hệ thống Đăng ký Giáo viên Hướng dẫn</p>
          <div className="mt-4 flex justify-center space-x-6">
            <a href="#" className="hover:text-white transition-colors">Hỗ trợ</a>
            <a href="#" className="hover:text-white transition-colors">Quy định</a>
            <a href="#" className="hover:text-white transition-colors">Liên hệ</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { TeacherStatus } from '../types';

interface Props {
  teachers: TeacherStatus[];
  onSubmit: (name: string, id: string, teacherId: string) => void;
}

const RegistrationForm: React.FC<Props> = ({ teachers, onSubmit }) => {
  const [name, setName] = useState('');
  const [studentId, setStudentId] = useState('');
  const [selectedTeacher, setSelectedTeacher] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim() || !studentId.trim() || !selectedTeacher) return;
    onSubmit(name.trim(), studentId.trim(), selectedTeacher);
    // Form is not cleared immediately to show success, App handles tab change
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label htmlFor="name" className="block text-sm font-semibold text-slate-700 mb-2">Họ và tên Sinh viên</label>
          <div className="relative">
            <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400">
              <i className="fas fa-user"></i>
            </span>
            <input
              type="text"
              id="name"
              required
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="block w-full pl-10 pr-3 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all"
              placeholder="Nguyễn Văn A"
            />
          </div>
        </div>

        <div>
          <label htmlFor="studentId" className="block text-sm font-semibold text-slate-700 mb-2">Mã số sinh viên (MSSV)</label>
          <div className="relative">
            <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400">
              <i className="fas fa-id-card"></i>
            </span>
            <input
              type="text"
              id="studentId"
              required
              value={studentId}
              onChange={(e) => setStudentId(e.target.value)}
              className="block w-full pl-10 pr-3 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all"
              placeholder="Ví dụ: 20211234"
            />
          </div>
        </div>
      </div>

      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-3">Chọn Giáo viên hướng dẫn</label>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {teachers.map((teacher) => {
            const isFull = teacher.currentRegistrations >= teacher.maxSlots;
            return (
              <label 
                key={teacher.id}
                className={`relative flex items-center p-4 border-2 rounded-xl cursor-pointer transition-all ${
                  selectedTeacher === teacher.id 
                    ? 'border-indigo-600 bg-indigo-50' 
                    : isFull 
                    ? 'border-slate-100 bg-slate-50 opacity-60 cursor-not-allowed' 
                    : 'border-slate-200 hover:border-indigo-300 hover:bg-slate-50'
                }`}
              >
                <input
                  type="radio"
                  name="teacher"
                  value={teacher.id}
                  disabled={isFull}
                  checked={selectedTeacher === teacher.id}
                  onChange={(e) => setSelectedTeacher(e.target.value)}
                  className="sr-only"
                />
                <div className="flex-1">
                  <p className="font-bold text-slate-800 leading-tight mb-1">{teacher.name}</p>
                  <p className="text-xs text-slate-500 italic mb-2">{teacher.title}</p>
                  <div className="flex items-center text-xs">
                    <span className={`px-2 py-0.5 rounded-full ${isFull ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                      {isFull ? 'Đã hết chỗ' : `Còn ${teacher.maxSlots - teacher.currentRegistrations} slot`}
                    </span>
                  </div>
                </div>
                {selectedTeacher === teacher.id && (
                  <div className="ml-2 text-indigo-600">
                    <i className="fas fa-check-circle text-xl"></i>
                  </div>
                )}
              </label>
            );
          })}
        </div>
      </div>

      <div className="pt-4">
        <button
          type="submit"
          disabled={!name || !studentId || !selectedTeacher}
          className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 disabled:cursor-not-allowed text-white font-bold py-4 rounded-xl shadow-lg transition-all transform hover:-translate-y-1 active:translate-y-0"
        >
          XÁC NHẬN ĐĂNG KÝ
        </button>
      </div>
    </form>
  );
};

export default RegistrationForm;

import React from 'react';
import { Registration, Teacher } from '../types';

interface Props {
  registrations: Registration[];
  teachers: Teacher[];
  onDelete: (id: string) => void;
}

const RegistrationList: React.FC<Props> = ({ registrations, teachers, onDelete }) => {
  const getTeacherName = (id: string) => {
    return teachers.find(t => t.id === id)?.name || 'Không xác định';
  };

  const formatDate = (timestamp: number) => {
    return new Intl.DateTimeFormat('vi-VN', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit'
    }).format(new Date(timestamp));
  };

  if (registrations.length === 0) {
    return (
      <div className="p-12 text-center text-slate-500">
        <i className="fas fa-folder-open text-5xl mb-4 text-slate-200"></i>
        <p className="text-lg">Chưa có sinh viên nào đăng ký.</p>
        <p className="text-sm">Hãy là người đầu tiên đăng ký giáo viên hướng dẫn!</p>
      </div>
    );
  }

  return (
    <div className="overflow-x-auto">
      <table className="w-full text-left border-collapse">
        <thead className="bg-slate-50 border-b border-slate-200">
          <tr>
            <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">STT</th>
            <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Sinh viên</th>
            <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">MSSV</th>
            <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Giáo viên hướng dẫn</th>
            <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Thời gian</th>
            <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Thao tác</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100">
          {[...registrations].sort((a, b) => b.timestamp - a.timestamp).map((reg, index) => (
            <tr key={reg.id} className="hover:bg-slate-50 transition-colors group">
              <td className="px-6 py-4 text-sm text-slate-500 font-medium">
                {registrations.length - index}
              </td>
              <td className="px-6 py-4">
                <div className="text-sm font-bold text-slate-900">{reg.studentName}</div>
              </td>
              <td className="px-6 py-4">
                <div className="text-sm font-mono text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded inline-block">
                  {reg.studentId}
                </div>
              </td>
              <td className="px-6 py-4">
                <div className="text-sm font-medium text-slate-700">
                   <i className="fas fa-chalkboard-user mr-2 text-slate-400"></i>
                   {getTeacherName(reg.teacherId)}
                </div>
              </td>
              <td className="px-6 py-4 text-sm text-slate-500">
                {formatDate(reg.timestamp)}
              </td>
              <td className="px-6 py-4 text-right">
                <button 
                  onClick={() => onDelete(reg.id)}
                  className="text-slate-400 hover:text-red-500 transition-colors p-2"
                  title="Hủy đăng ký"
                >
                  <i className="fas fa-trash-alt"></i>
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default RegistrationList;
